// Supports defaultValue and basic string interpolation with {{key}} syntax.
const _stableI18n = {
  t: (key, options) => {
    const template = options?.defaultValue || key
    return options
      ? template.replace(/\{\{(\w+)\}\}/g, (_, token) =>
          String(options[token] ?? `{{${token}}}`)
        )
      : template
  },
  i18n: { language: 'en' }
}
